    "contracts/src/library/OracleLibrary.sol": {
      "content": "// SPDX-License-Identifier: UNLICENSED
pragma solidity 0.8.26;

// Uniswap
import {IUniswapV3Pool} from "../../lib/v3-core/contracts/interfaces/IUniswapV3Pool.sol";

// OpenZeppelin
import {Math} from "../../lib/openzeppelin-contracts/contracts/utils/math/Math.sol";

/**
 * @notice Adapted Uniswap V3 OracleLibrary computation to be compliant with Solidity 0.8.x and later.
 *
 * Documentation for Auditors:
 *
 * Solidity Version: Updated the Solidity version pragma to ^0.8.0. This change ensures compatibility
 * with Solidity version 0.8.x.
 *
 * Safe Arithmetic Operations: Solidity 0.8.x automatically checks for arithmetic overflows/underflows.
 * Therefore, the code no longer needs to use SafeMath library (or similar) for basic arithmetic operations.
 * This change simplifies the code and reduces the potential for errors related to manual overflow/underflow checking.
 *
 * Overflow/Underflow: With the introduction of automatic overflow/underflow checks in Solidity 0.8.x, the code is inherently
 * safer and less prone to certain types of arithmetic errors.
 *
 * Removal of SafeMath Library: Since Solidity 0.8.x handles arithmetic operations safely, the use of SafeMath library
 * is omitted in this update.
 *
 * Git-style diff for the `consult` function:
 *
 * ```diff
 * function consult(address pool, uint32 secondsAgo)
 *     internal
 *     view
 *     returns (int24 arithmeticMeanTick, uint128 harmonicMeanLiquidity)
 * {
 *     require(secondsAgo != 0, 'BP');
 *
 *     uint32[] memory secondsAgos = new uint32[](2);
 *     secondsAgos[0] = secondsAgo;
 *     secondsAgos[1] = 0;
 *
 *     (int56[] memory tickCumulatives, uint160[] memory secondsPerLiquidityCumulativeX128s) =
 *         IUniswapV3Pool(pool).observe(secondsAgos);
 *
 *     int56 tickCumulativesDelta = tickCumulatives[1] - tickCumulatives[0];
 *     uint160 secondsPerLiquidityCumulativesDelta =
 *         secondsPerLiquidityCumulativeX128s[1] - secondsPerLiquidityCumulativeX128s[0];
 *
 * -   arithmeticMeanTick = int24(tickCumulativesDelta / secondsAgo);
 * +   int56 secondsAgoInt56 = int56(uint56(secondsAgo));
 * +   arithmeticMeanTick = int24(tickCumulativesDelta / secondsAgoInt56);
 *     // Always round to negative infinity
 * -   if (tickCumulativesDelta < 0 && (tickCumulativesDelta % secondsAgo != 0)) arithmeticMeanTick--;
 * +   if (tickCumulativesDelta < 0 && (tickCumulativesDelta % secondsAgoInt56 != 0)) arithmeticMeanTick--;
 *
 * -   uint192 secondsAgoX160 = uint192(secondsAgo) * type(uint160).max;
 * +   uint192 secondsAgoUint192 = uint192(secondsAgo);
 * +   uint192 secondsAgoX160 = secondsAgoUint192 * type(uint160).max;
 *     harmonicMeanLiquidity = uint128(secondsAgoX160 / (uint192(secondsPerLiquidityCumulativesDelta) << 32));
 * }
 * ```
 */

/// @title Oracle library
/// @notice Provides functions to integrate with V3 pool oracle
library OracleLibrary {
    /// @notice Calculates time-weighted means of tick and liquidity for a given Uniswap V3 pool
    /// @param pool Address of the pool that we want to observe
    /// @param secondsAgo Number of seconds in the past from which to calculate the time-weighted means
    /// @return arithmeticMeanTick The arithmetic mean tick from (block.timestamp - secondsAgo) to block.timestamp
    /// @return harmonicMeanLiquidity The harmonic mean liquidity from (block.timestamp - secondsAgo) to block.timestamp
    function consult(
        address pool,
        uint32 secondsAgo
    )
        internal
        view
        returns (int24 arithmeticMeanTick, uint128 harmonicMeanLiquidity)
    {
        require(secondsAgo != 0, "BP");

        uint32[] memory secondsAgos = new uint32[](2);
        secondsAgos[0] = secondsAgo;
        secondsAgos[1] = 0;

        (
            int56[] memory tickCumulatives,
            uint160[] memory secondsPerLiquidityCumulativeX128s
        ) = IUniswapV3Pool(pool).observe(secondsAgos);

        int56 tickCumulativesDelta = tickCumulatives[1] - tickCumulatives[0];
        uint160 secondsPerLiquidityCumulativesDelta = secondsPerLiquidityCumulativeX128s[
                1
            ] - secondsPerLiquidityCumulativeX128s[0];

        // Safe casting of secondsAgo to int56 for division
        int56 secondsAgoInt56 = int56(uint56(secondsAgo));
        arithmeticMeanTick = int24(tickCumulativesDelta / secondsAgoInt56);
        // Always round to negative infinity
        if (
            tickCumulativesDelta < 0 &&
            (tickCumulativesDelta % secondsAgoInt56 != 0)
        ) arithmeticMeanTick--;

        // Safe casting of secondsAgo to uint192 for multiplication
        uint192 secondsAgoUint192 = uint192(secondsAgo);
        harmonicMeanLiquidity = uint128(
            (secondsAgoUint192 * uint192(type(uint160).max)) /
                (uint192(secondsPerLiquidityCumulativesDelta) << 32)
        );
    }

    /// @notice Given a pool, it returns the number of seconds ago of the oldest stored observation
    /// @param pool Address of Uniswap V3 pool that we want to observe
    /// @return secondsAgo The number of seconds ago of the oldest observation stored for the pool
    function getOldestObservationSecondsAgo(
        address pool
    ) internal view returns (uint32 secondsAgo) {
        (
            ,
            ,
            uint16 observationIndex,
            uint16 observationCardinality,
            ,
            ,

        ) = IUniswapV3Pool(pool).slot0();
        require(observationCardinality > 0, "NI");

        (uint32 observationTimestamp, , , bool initialized) = IUniswapV3Pool(
            pool
        ).observations((observationIndex + 1) % observationCardinality);

        // The next index might not be initialized if the cardinality is in the process of increasing
        // In this case the oldest observation is always in index 0
        if (!initialized) {
            (observationTimestamp, , , ) = IUniswapV3Pool(pool).observations(0);
        }

        secondsAgo = uint32(block.timestamp) - observationTimestamp;
    }

    /// @notice Given a tick and a token amount, calculates the amount of token received in exchange
    /// a slightly modified version of the UniSwap library getQuoteAtTick to accept a sqrtRatioX96 as input parameter
    /// @param sqrtRatioX96 The sqrt ration
    /// @param baseAmount Amount of token to be converted
    /// @param baseToken Address of an ERC20 token contract used as the baseAmount denomination
    /// @param quoteToken Address of an ERC20 token contract used as the quoteAmount denomination
    /// @return quoteAmount Amount of quoteToken received for baseAmount of baseToken
    function getQuoteForSqrtRatioX96(
        uint160 sqrtRatioX96,
        uint256 baseAmount,
        address baseToken,
        address quoteToken
    ) internal pure returns (uint256 quoteAmount) {
        // Calculate quoteAmount with better precision if it doesn't overflow when multiplied by itself
        if (sqrtRatioX96 <= type(uint128).max) {
            uint256 ratioX192 = uint256(sqrtRatioX96) * sqrtRatioX96;
            quoteAmount = baseToken < quoteToken
                ? Math.mulDiv(ratioX192, baseAmount, 1 << 192)
                : Math.mulDiv(1 << 192, baseAmount, ratioX192);
        } else {
            uint256 ratioX128 = Math.mulDiv(
                sqrtRatioX96,
                sqrtRatioX96,
                1 << 64
            );
            quoteAmount = baseToken < quoteToken
                ? Math.mulDiv(ratioX128, baseAmount, 1 << 128)
                : Math.mulDiv(1 << 128, baseAmount, ratioX128);
        }
    }
}
"
    },
    "contracts/src/Torus.sol": {
      "content": "// SPDX-License-Identifier: MIT
pragma solidity 0.8.26;

/* === OZ === */
import {ERC20} from "../lib/openzeppelin-contracts/contracts/token/ERC20/ERC20.sol";
import {ERC20Burnable} from "../lib/openzeppelin-contracts/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import {Ownable} from "../lib/openzeppelin-contracts/contracts/access/Ownable.sol";

/* = SYSTEM */
import {TorusCreateAndStake} from "./TorusCreateAndStake.sol";
import {TorusBuyAndProcess} from "./TorusBuyAndProcess.sol";

/* = LIBS =  */
import {Math} from "../lib/openzeppelin-contracts/contracts/utils/math/Math.sol";

/* = UNIV3 = */
import {IUniswapV3Pool} from "../lib/v3-core/contracts/interfaces/IUniswapV3Pool.sol";
import {INonfungiblePositionManager} from "../lib/v3-periphery/contracts/interfaces/INonfungiblePositionManager.sol";

import "./const/BuyAndProcessConst.sol";

/**
 * @title Torus.win
 * @author BuildTheTech.com
 * @dev ERC20 token contract for Torus tokens.
 * @notice It can be minted by TorusCreate during cycles
 */
contract Torus is ERC20Burnable, Ownable {
    /* ==== IMMUTABLES ==== */

    TorusCreateAndStake public immutable create;
    TorusBuyAndProcess public immutable buyAndProcess;
    address public titanXTorusPool;

    address public genesisWallet;
    uint256 public genesisFee = 369;
    uint256 public burnFee = 6400;
    uint256 public buildFee = 2800;
    uint256 public titanXBurnFee = 431;

    /* ==== ERRORS ==== */

    error OnlyCreate();
    error OnlyBuyAndProcess();

    /* ==== CONSTRUCTOR ==== */

    /**
     * @dev Sets the create and buy and process contract address.
     * @param _torusCreateStartTimestamp The start of the first create cycle
     * @param _torusBuyAndProcessStartTimestamp The start of the buy and process contract
     * @param _owner The owner
     */
    constructor(
        uint32 _torusCreateStartTimestamp,
        uint32 _torusBuyAndProcessStartTimestamp,
        address _owner
    ) payable ERC20("Torus", "TORUS") Ownable(msg.sender) {
        buyAndProcess = new TorusBuyAndProcess(
            _torusBuyAndProcessStartTimestamp,
            _owner
        );
        create = new TorusCreateAndStake(
            address(buyAndProcess),
            address(this),
            _torusCreateStartTimestamp
        );

        buyAndProcess.setCreateAndStakeContract(address(create));
        genesisWallet = GENESIS_WALLET;

        createTitanXTorusPool(
            TITAN_X_ADDRESS,
            INITIAL_TITAN_X_FOR_LIQ
        );
    }

    /* == MODIFIERS == */

    /// @dev Modifier to ensure the function is called only by the create contract.
    modifier onlyCreate() {
        _onlyCreate();
        _;
    }

    /// @dev Modifier to ensure the function is called only by the buy and process contract.
    modifier onlyBuyAndProcess() {
        _onlyBuyAndProcess();
        _;
    }

    /* == EXTERNAL == */

    /**
     * @notice Creates(mints) TORUS tokens to a specified address.
     * @notice This is only callable by the TorusCreate contract
     * @param _to The address to mint the tokens to.
     * @param _amount The amount of tokens to mint.
     */
    function mint(address _to, uint256 _amount) external onlyCreate {
        _mint(_to, _amount);
    }

    /// @notice Mints torus tokens for the initial LP creation
    function createTokensForLP() external onlyBuyAndProcess {
        _mint(address(buyAndProcess), INITIAL_LP_MINT);
    }

    /* == INTERNAL == */

    function _onlyBuyAndProcess() internal view {
        if (msg.sender != address(buyAndProcess)) revert OnlyBuyAndProcess();
    }

    function _onlyCreate() internal view {
        if (msg.sender != address(create)) revert OnlyCreate();
    }

    ///@notice - Creates the TitanX/TORUS Pool on uniswapV3
    ///@notice - Only called once when liquidity is added from BuyAndProcess
    function createTitanXTorusPool(
        address _titanX,
        uint256 _titanXReceived
    ) internal returns (address _titanXTorusPool) {
        address _torus = address(this);

        uint160 sqrtPriceX96;

        (address token0, address token1) = _titanX < _torus
            ? (_titanX, _torus)
            : (_torus, _titanX);

        uint256 titanXAmount = _titanXReceived;
        uint256 torusAmount = INITIAL_LP_MINT;

        (uint256 amount0, uint256 amount1) = token0 == _titanX
            ? (titanXAmount, torusAmount)
            : (torusAmount, titanXAmount);

        sqrtPriceX96 = uint160(
            (Math.sqrt((amount1 * 1e18) / amount0) * 2 ** 96) / 1e9
        );

        INonfungiblePositionManager manager = INonfungiblePositionManager(
            UNISWAP_V3_POSITION_MANAGER
        );

        titanXTorusPool = manager.createAndInitializePoolIfNecessary(
            token0,
            token1,
            POOL_FEE,
            sqrtPriceX96
        );

        _titanXTorusPool = titanXTorusPool;

        IUniswapV3Pool(titanXTorusPool).increaseObservationCardinalityNext(
            uint16(100)
        );

    }

    function mintTokensForLP() external onlyBuyAndProcess {
        _mint(address(buyAndProcess), INITIAL_LP_MINT);
    }

    /* ================================================================
                                ADMIN FUNCTIONS
       ================================================================ */
    function setFees(uint256 _genesisFee, uint256 _burnFee, uint256 _buildFee, uint256 _titanXBurnFee) external onlyOwner {
        genesisFee = _genesisFee;
        burnFee = _burnFee;
        buildFee = _buildFee;
        titanXBurnFee = _titanXBurnFee;
        require(genesisFee <= 369, "Maximum genesis fee is 3.69%");
        require(buildFee <= 2800, "Maximum build fee is 28%");
        require(titanXBurnFee <= 431, "Maximum TitanX burn fee is 4.31%");
        require(genesisFee + burnFee + buildFee + titanXBurnFee == 10000, "Must equal 100%.");
    }

    function setGenesisWallet(address _newGenesis) external onlyOwner {
        require(_newGenesis != address(0), "Invalid address");
        genesisWallet = _newGenesis;
    }
}
"
    },
    "contracts/src/TorusBuyAndProcess.sol": {
      "content": "// SPDX-License-Identifier: UNLICENSED
pragma solidity 0.8.26;

/* === UNIV3 === */
import {TransferHelper} from "../lib/v3-periphery/contracts/libraries/TransferHelper.sol";
import {INonfungiblePositionManager} from "../lib/v3-periphery/contracts/interfaces/INonfungiblePositionManager.sol";
import {TickMath} from "../lib/v3-core/contracts/libraries/TickMath.sol";
import {OracleLibrary} from "./library/OracleLibrary.sol";
import {ISwapRouter} from "../lib/v3-periphery/contracts/interfaces/ISwapRouter.sol";

/* === OZ === */
import {ReentrancyGuard} from "../lib/openzeppelin-contracts/contracts/utils/ReentrancyGuard.sol";
import {Ownable2Step, Ownable} from "../lib/openzeppelin-contracts/contracts/access/Ownable2Step.sol";
import {IERC20} from "../lib/openzeppelin-contracts/contracts/token/ERC20/IERC20.sol";
import {ERC20Burnable} from "../lib/openzeppelin-contracts/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import {IERC721Receiver} from "@openzeppelin/contracts/token/ERC721/IERC721Receiver.sol";

/* === CONST === */
import "./const/BuyAndProcessConst.sol";

/* === SYSTEM === */
import {Torus} from "./Torus.sol";
import {TorusCreateAndStake} from "./TorusCreateAndStake.sol";

/**
 * @title TorusBuyAndProcess
 * @dev This contract handles two separate flows:
 *       - The “burn” flow: users can swap TitanX/ETH for Torus and burn the Torus tokens.
 *       - The “build” flow: users can swap funds for TitanX, swap half for Torus and then add liquidity.
 *
 * Both flows use separate interval‐mechanisms, daily allocations, and slippage settings.
 */
contract TorusBuyAndProcess is ReentrancyGuard, Ownable2Step, IERC721Receiver {
    using TransferHelper for IERC20;

    /* ================================================================
                           COMMON CONSTANTS / IMMUTABLE
       ================================================================ */
    INonfungiblePositionManager public constant POSITION_MANAGER =
        INonfungiblePositionManager(UNISWAP_V3_POSITION_MANAGER);

    ERC20Burnable private immutable titanX;
    Torus public immutable torusToken;
    TorusCreateAndStake public torusCreateAndStake;
    uint32 public immutable startTimeStamp;

    /* ================================================================
                           BURN (BuyAndBurn) VARIABLES
       ================================================================ */

    struct IntervalBurn {
        uint128 amountAllocated;
        uint128 amountBurned;
    }

    struct IntervalBuild {
        uint128 amountAllocated;
        uint128 amountBurned;
    }

    struct LP {
        uint248 tokenId;
        bool isTitanXToken0;
    }

    LP public lpToken;

    bool public liquidityAdded;

    uint256 public totalTorusBurnt;
    uint256 public totalTitanXBurnt;
    uint256 public titanXUsedForBurns;
    uint256 public ethUsedForBurns;
    uint256 public titanXUsedForBuilds;
    uint256 public ethUsedForBuilds;

    uint256 public DAILY_ALLOCATION_TITAN_X_BURNING = 100; // in basis points (e.g. 100 = 1%)
    uint256 public DAILY_ALLOCATION_ETH_BURNING = 100;
    uint256 public DAILY_ALLOCATION_TITAN_X_BUILDING = 100; // in basis points (e.g. 100 = 1%)
    uint256 public DAILY_ALLOCATION_ETH_BUILDING = 100;

